#include <iostream>
using namespace std;

class Rectangle {
private:
 int length;
 int breadth;
public:
 // Parameterized constructor with initialization list
 Rectangle(int l, int b) : length(l), breadth(b) {
 cout << "Constructor called" << endl;
 }

 int area() {
 return length * breadth;
 }

 void display() {
 cout << "Length: " << length << ", Breadth: " << breadth << endl;
 }
};

int main() {
 Rectangle r1(10, 5);
 r1.display();
 cout << "Area: " << r1.area() << endl;
 return 0;
}

#include <iostream>
using namespace std;

class Box {
private:
 int length, width, height;
public:
 // Default constructor
 Box() : length(0), width(0), height(0) {
 cout << "Default constructor" << endl;
 }

 // Parameterized constructor - single parameter
 Box(int side) : length(side), width(side), height(side) {
 cout << "Cube constructor" << endl;
 }

 // Parameterized constructor - three parameters
 Box(int l, int w, int h) : length(l), width(w), height(h) {
 cout << "Box constructor" << endl;
 }

 int volume() {
 return length * width * height;
 }
};

int main() {
 Box b1; // Calls default
 Box b2(5); // Calls single param (cube)
 Box b3(2, 3, 4); // Calls three params

 cout << "Volumes: " << b1.volume() << " " << b2.volume() << " " << b3.volume() << endl;
 return 0;
}

#include <iostream>
using namespace std;

class Point {
private:
 int x, y;
public:
 // Parameterized constructor
 Point(int a, int b) : x(a), y(b) {
 cout << "Parameterized constructor called" << endl;
 }

 // Copy constructor
 Point(const Point& p) : x(p.x), y(p.y) {
 cout << "Copy constructor called" << endl;
 }

 void display() {
 cout << "x = " << x << ", y = " << y << endl;
 }
};

void func(Point p) {
 // Copy constructor called when passing by value
 p.display();
}

int main() {
 Point p1(10, 20); // Parameterized constructor
 Point p2 = p1; // Copy constructor
 Point p3(p1); // Copy constructor

 func(p1); // Copy constructor called

 return 0;
}

#include <iostream>
using namespace std;

class MyString {
private:
 string data;
 int size;
public:
 // Without explicit - allows implicit conversion
 /* This would cause issues - implicit conversion enabled */

 // With explicit - prevents implicit conversion
 explicit MyString(int n) : data(n, ' '), size(n) {
 cout << "Explicit constructor called with " << n << endl;
 }

 explicit MyString(const char* str) {
 data = str;
 size = data.length();
 cout << "String constructor called" << endl;
 }

 void display() {
 cout << "Data: " << data << ", Size: " << size << endl;
 }
};

int main() {
 // These work - explicit calls
 MyString s1(10); // Explicit call - OK
 MyString s2("Hello"); // Explicit call - OK

 // This would cause error with explicit:
 // MyString s3 = 10; // Error: implicit conversion not allowed
 // func(10); // Error: implicit conversion not allowed

 s1.display();
 s2.display();
 return 0;
}
